import pandas as pd
import numpy as np
import random
import string

def generate_random_string(length):
    letters = string.ascii_letters
    return ''.join(random.choice(letters) for i in range(length))

def generate_random_id():
    return ''.join(random.choices(string.ascii_uppercase + string.digits, k=8))

def generate_random_age():
    return random.randint(1, 100)

def generate_random_sex():
    return random.choice(['Male', 'Female', 'Other'])

def generate_random_lf():
    return generate_random_string(10)

def generate_random_cp():
    return random.randint(1, 10)

def generate_dataframe(num_rows):
    data = []
    for _ in range(num_rows):
        id_val = generate_random_id()
        age = generate_random_age()
        sex = generate_random_sex()
        lf = generate_random_lf()
        cp = generate_random_cp()
        data.append([id_val, age, sex, lf, cp])

    df = pd.DataFrame(data, columns=['ID', 'age', 'sex', 'LF', 'CP'])
    return df

def anonymize_id(df, id_column):
    df[id_column] = 'Fih@ZiGsfEjrg3Tu'
    return df

def anonymize_age(df, age_column):
    df[age_column] = np.random.randint(1, 100, size=len(df))
    return df

num_rows = 100
df = generate_dataframe(num_rows)
df = anonymize_id(df, 'ID')
df = anonymize_age(df, 'age')

print(df.to_string())

